70		{
71			std::string opt_clean_args;
72			std::string opt_expr_args;
73			std::string opt_reduce_args;
74			std::string opt_merge_args;
75			std::string opt_dff_args;
76			bool opt_share = false;
77			bool fast_mode = false;
78			bool noff_mode = false;
79			bool hier_mode = false;
80	
81			log_header(design, "Executing OPT pass (performing simple optimizations).\n");
82			log_push();
83	
84			size_t argidx;
85			for (argidx = 1; argidx < args.size(); argidx++) {
86				if (args[argidx] == "-purge") {
87					opt_clean_args += " -purge";
88					continue;
89				}
90				if (args[argidx] == "-mux_undef") {
91					opt_expr_args += " -mux_undef";
