112					opt_expr_args += " -full";
113					opt_reduce_args += " -full";
114					opt_share = true;
115					continue;
116				}
117				if (args[argidx] == "-keepdc") {
118					opt_expr_args += " -keepdc";
119					opt_dff_args += " -keepdc";
120					opt_merge_args += " -keepdc";
121					continue;
122				}
123				if (args[argidx] == "-nodffe") {
124					opt_dff_args += " -nodffe";
125					continue;
126				}
127				if (args[argidx] == "-nosdff") {
128					opt_dff_args += " -nosdff";
129					continue;
130				}
131				if (args[argidx] == "-sat") {
132					opt_dff_args += " -sat";
133					continue;
134				}
135				if (args[argidx] == "-share_all") {
136					opt_merge_args += " -share_all";
137					continue;
138				}
139				if (args[argidx] == "-fast") {
140					fast_mode = true;
141					continue;
142				}
143				if (args[argidx] == "-noff") {
144					noff_mode = true;
