169				}
170				Pass::call(design, "opt_clean" + opt_clean_args);
171			}
172			else
173			{
174				Pass::call(design, "opt_expr" + opt_expr_args);
175				Pass::call(design, "opt_merge -nomux" + opt_merge_args);
176				while (1) {
177					design->scratchpad_unset("opt.did_something");
178					Pass::call(design, "opt_muxtree");
179					Pass::call(design, "opt_reduce" + opt_reduce_args);
180					Pass::call(design, "opt_merge" + opt_merge_args);
181					if (opt_share)
182						Pass::call(design, "opt_share");
183					if (!noff_mode)
184						Pass::call(design, "opt_dff" + opt_dff_args);
185					if (hier_mode)
