20	#include "kernel/register.h"
21	#include "kernel/ffinit.h"
22	#include "kernel/sigtools.h"
23	#include "kernel/log.h"
24	#include "kernel/celltypes.h"
25	#include "kernel/threading.h"
26	#include "libs/sha1/sha1.h"
27	#include <stdlib.h>
28	#include <stdio.h>
29	#include <algorithm>
30	#include <set>
31	#include <unordered_map>
32	#include <array>
33	
34	
35	USING_YOSYS_NAMESPACE
36	PRIVATE_NAMESPACE_BEGIN
37	
38	template <typename T, typename U>
39	inline Hasher hash_pair(const T &t, const U &u) { return hash_ops<std::pair<T, U>>::hash(t, u); }
40	
41	// Some cell and its hash value.
42	struct CellHash
43	{
44		// Index of a cell in the module
45		int cell_index;
46		Hasher::hash_t hash_value;
47	};
48	
49	// The algorithm:
50	// 1) Compute and store the hashes of all relevant cells, in parallel.
51	// 2) Given N = the number of threads, partition the cells into N buckets by hash value:
52	// bucket k contains the cells whose hash value mod N = k.
53	// 3) For each bucket in parallel, build a hashtable of that bucket’s cells (using the
54	// precomputed hashes) and record the duplicates found.
55	// 4) On the main thread, process the list of duplicates to remove cells.
56	// For efficiency we fuse the second step into the first step by having the parallel
57	// threads write the cells into buckets directly.
58	// To avoid synchronization overhead, we divide each bucket into N shards. Each
59	// thread j adds a cell to bucket k by writing to shard j of bucket k —
60	// no synchronization required. In the next phase, thread k builds the hashtable for
61	// bucket k by iterating over all shards of the bucket.
62	
63	// The input to each thread in the "compute cell hashes" phase.
64	struct CellRange
65	{
66		int begin;
67		int end;
68	};
69	
70	// The output from each thread in the "compute cell hashes" phase.
71	struct CellHashes
72	{
73		// Entry i contains the hashes where hash_value % bucketed_cell_hashes.size() == i
74		std::vector<std::vector<CellHash>> bucketed_cell_hashes;
75	};
76	
77	// A duplicate cell that has been found.
78	struct DuplicateCell
79	{
80		// Remove this cell from the design
81		int remove_cell;
82		// ... and use this cell instead.
83		int keep_cell;
84	};
85	
86	// The input to each thread in the "find duplicate cells" phase.
87	// Shards of buckets of cell hashes
88	struct Shards
89	{
90		std::vector<std::vector<std::vector<CellHash>>> &bucketed_cell_hashes;
91	};
92	
93	// The output from each thread in the "find duplicate cells" phase.
94	struct FoundDuplicates
95	{
96		std::vector<DuplicateCell> duplicates;
97	};
98	
99	struct OptMergeThreadWorker
100	{
101		const RTLIL::Module *module;
102		const SigMap &assign_map;
103		const FfInitVals &initvals;
104		const CellTypes &ct;
105		int workers;
106		bool mode_share_all;
107		bool mode_keepdc;
108	
109		static Hasher hash_pmux_in(const SigSpec& sig_s, const SigSpec& sig_b, Hasher h)
110		{
111			int s_width = GetSize(sig_s);
112			int width = GetSize(sig_b) / s_width;
113	
114			hashlib::commutative_hash comm;
115			for (int i = 0; i < s_width; i++)
116				comm.eat(hash_pair(sig_s[i], sig_b.extract(i*width, width)));
117	
118			return comm.hash_into(h);
119		}
120	
121		static void sort_pmux_conn(dict<RTLIL::IdString, RTLIL::SigSpec> &conn)
122		{
123			const SigSpec &sig_s = conn.at(ID::S);
124			const SigSpec &sig_b = conn.at(ID::B);
125	
126			int s_width = GetSize(sig_s);
127			int width = GetSize(sig_b) / s_width;
128	
129			vector<pair<SigBit, SigSpec>> sb_pairs;
130			for (int i = 0; i < s_width; i++)
131				sb_pairs.push_back(pair<SigBit, SigSpec>(sig_s[i], sig_b.extract(i*width, width)));
132	
133			std::sort(sb_pairs.begin(), sb_pairs.end());
134	
135			conn[ID::S] = SigSpec();
136			conn[ID::B] = SigSpec();
137	
138			for (auto &it : sb_pairs) {
139				conn[ID::S].append(it.first);
140				conn[ID::B].append(it.second);
141			}
142		}
143	
144		Hasher hash_cell_inputs(const RTLIL::Cell *cell, Hasher h) const
145		{
146			// TODO: when implemented, use celltypes to match:
147			// (builtin || stdcell) && (unary || binary) && symmetrical
148			if (cell->type.in(ID($and), ID($or), ID($xor), ID($xnor), ID($add), ID($mul),
149					ID($logic_and), ID($logic_or), ID($_AND_), ID($_OR_), ID($_XOR_))) {
150				hashlib::commutative_hash comm;
151				comm.eat(assign_map(cell->getPort(ID::A)));
152				comm.eat(assign_map(cell->getPort(ID::B)));
153				h = comm.hash_into(h);
154			} else if (cell->type.in(ID($reduce_xor), ID($reduce_xnor))) {
155				SigSpec a = assign_map(cell->getPort(ID::A));
156				a.sort();
157				h = a.hash_into(h);
158			} else if (cell->type.in(ID($reduce_and), ID($reduce_or), ID($reduce_bool))) {
159				SigSpec a = assign_map(cell->getPort(ID::A));
160				a.sort_and_unify();
161				h = a.hash_into(h);
162			} else if (cell->type == ID($pmux)) {
163				SigSpec sig_s = assign_map(cell->getPort(ID::S));
164				SigSpec sig_b = assign_map(cell->getPort(ID::B));
165				h = hash_pmux_in(sig_s, sig_b, h);
166				h = assign_map(cell->getPort(ID::A)).hash_into(h);
167			} else {
168				hashlib::commutative_hash comm;
169				for (const auto& [port, sig] : cell->connections()) {
170					if (cell->output(port))
171						continue;
172					comm.eat(hash_pair(port, assign_map(sig)));
173				}
174				h = comm.hash_into(h);
175				if (cell->is_builtin_ff())
176					h = initvals(cell->getPort(ID::Q)).hash_into(h);
177			}
178			return h;
179		}
180	
181		static Hasher hash_cell_parameters(const RTLIL::Cell *cell, Hasher h)
182		{
183			hashlib::commutative_hash comm;
184			for (const auto& param : cell->parameters) {
185				comm.eat(param);
186			}
187			return comm.hash_into(h);
188		}
189	
190		Hasher hash_cell_function(const RTLIL::Cell *cell, Hasher h) const
191		{
192			h.eat(cell->type);
193			h = hash_cell_inputs(cell, h);
194			h = hash_cell_parameters(cell, h);
195			return h;
196		}
197	
198		bool compare_cell_parameters_and_connections(const RTLIL::Cell *cell1, const RTLIL::Cell *cell2) const
199		{
200			if (cell1 == cell2) return true;
201			if (cell1->type != cell2->type) return false;
202	
203			if (cell1->parameters != cell2->parameters)
204				return false;
205			if (cell1->connections_.size() != cell2->connections_.size())
206				return false;
207			for (const auto &it : cell1->connections_)
208				if (!cell2->connections_.count(it.first))
209					return false;
210	
211			decltype(Cell::connections_) conn1, conn2;
212			conn1.reserve(cell1->connections_.size());
213			conn2.reserve(cell1->connections_.size());
214	
215			for (const auto &it : cell1->connections_) {
216				if (cell1->output(it.first)) {
217					if (it.first == ID::Q && cell1->is_builtin_ff()) {
218						// For the 'Q' output of state elements,
219						//   use the (* init *) attribute value
220						conn1[it.first] = initvals(it.second);
221						conn2[it.first] = initvals(cell2->getPort(it.first));
222					}
223					else {
224						conn1[it.first] = RTLIL::SigSpec();
225						conn2[it.first] = RTLIL::SigSpec();
226					}
227				}
228				else {
229					conn1[it.first] = assign_map(it.second);
230					conn2[it.first] = assign_map(cell2->getPort(it.first));
231				}
232			}
233	
234			if (cell1->type.in(ID($and), ID($or), ID($xor), ID($xnor), ID($add), ID($mul),
235					ID($logic_and), ID($logic_or), ID($_AND_), ID($_OR_), ID($_XOR_))) {
236				if (conn1.at(ID::A) < conn1.at(ID::B)) {
237					std::swap(conn1[ID::A], conn1[ID::B]);
238				}
239				if (conn2.at(ID::A) < conn2.at(ID::B)) {
240					std::swap(conn2[ID::A], conn2[ID::B]);
241				}
242			} else
243			if (cell1->type.in(ID($reduce_xor), ID($reduce_xnor))) {
244				conn1[ID::A].sort();
245				conn2[ID::A].sort();
246			} else
247			if (cell1->type.in(ID($reduce_and), ID($reduce_or), ID($reduce_bool))) {
248				conn1[ID::A].sort_and_unify();
249				conn2[ID::A].sort_and_unify();
250			} else
251			if (cell1->type == ID($pmux)) {
252				sort_pmux_conn(conn1);
253				sort_pmux_conn(conn2);
254			}
255	
256			return conn1 == conn2;
257		}
258	
259		bool has_dont_care_initval(const RTLIL::Cell *cell) const
260		{
261			if (!cell->is_builtin_ff())
262				return false;
263	
264			return !initvals(cell->getPort(ID::Q)).is_fully_def();
265		}
266	
267		OptMergeThreadWorker(const RTLIL::Module *module, const FfInitVals &initvals,
268				const SigMap &assign_map, const CellTypes &ct, int workers,
269				bool mode_share_all, bool mode_keepdc) :
270			module(module), assign_map(assign_map), initvals(initvals), ct(ct),
271			workers(workers), mode_share_all(mode_share_all), mode_keepdc(mode_keepdc)
272		{
273		}
274	
275		CellHashes compute_cell_hashes(const CellRange &cell_range) const
276		{
277			std::vector<std::vector<CellHash>> bucketed_cell_hashes(workers);
278			for (int cell_index = cell_range.begin; cell_index < cell_range.end; ++cell_index) {
279				const RTLIL::Cell *cell = module->cell_at(cell_index);
280				if (!module->selected(cell))
281					continue;
282				if (cell->type.in(ID($meminit), ID($meminit_v2), ID($mem), ID($mem_v2))) {
283					// Ignore those for performance: meminit can have an excessively large port,
284					// mem can have an excessively large parameter holding the init data
285					continue;
286				}
287				if (cell->type == ID($scopeinfo))
288					continue;
289				if (mode_keepdc && has_dont_care_initval(cell))
290					continue;
291				if (!cell->known())
292					continue;
293				if (!mode_share_all && !ct.cell_known(cell->type))
294					continue;
295	
296				Hasher::hash_t h = hash_cell_function(cell, Hasher()).yield();
297				int bucket_index = h % workers;
298				bucketed_cell_hashes[bucket_index].push_back({cell_index, h});
299			}
300			return {std::move(bucketed_cell_hashes)};
301		}
302	
303		FoundDuplicates find_duplicate_cells(int index, const Shards &in) const
304		{
305			// We keep a set of known cells. They're hashed with our hash_cell_function
306			// and compared with our compare_cell_parameters_and_connections.
307			struct CellHashOp {
308				std::size_t operator()(const CellHash &c) const {
309					return (std::size_t)c.hash_value;
310				}
311			};
312			struct CellEqualOp {
313				const OptMergeThreadWorker& worker;
314				CellEqualOp(const OptMergeThreadWorker& w) : worker(w) {}
315				bool operator()(const CellHash &lhs, const CellHash &rhs) const {
316					return worker.compare_cell_parameters_and_connections(
317							worker.module->cell_at(lhs.cell_index),
318							worker.module->cell_at(rhs.cell_index));
319				}
320			};
321			std::unordered_set<
322				CellHash,
323				CellHashOp,
324				CellEqualOp> known_cells(0, CellHashOp(), CellEqualOp(*this));
325	
326			std::vector<DuplicateCell> duplicates;
327			for (std::vector<std::vector<CellHash>> &buckets : in.bucketed_cell_hashes) {
328				// Clear out our buckets as we go. This keeps the work of deallocation
329				// off the main thread.
330				std::vector<CellHash> bucket = std::move(buckets[index]);
331				for (CellHash c : bucket) {
332					auto [cell_in_map, inserted] = known_cells.insert(c);
333					if (inserted)
334						continue;
335					CellHash map_c = *cell_in_map;
336					if (module->cell_at(c.cell_index)->has_keep_attr()) {
337						if (module->cell_at(map_c.cell_index)->has_keep_attr())
338							continue;
339						known_cells.erase(map_c);
340						known_cells.insert(c);
341						std::swap(c, map_c);
342					}
343					duplicates.push_back({c.cell_index, map_c.cell_index});
344				}
345			}
346			return {duplicates};
347		}
348	};
349	
350	template <typename T>
351	void initialize_queues(std::vector<ConcurrentQueue<T>> &queues, int size) {
352		queues.reserve(size);
353		for (int i = 0; i < size; ++i)
354			queues.emplace_back(1);
355	}
356	
357	struct OptMergeWorker
358	{
359		int total_count;
360	
361		OptMergeWorker(RTLIL::Module *module, const CellTypes &ct, bool mode_share_all, bool mode_keepdc) :
362			total_count(0)
363		{
364			SigMap assign_map(module);
365			FfInitVals initvals;
366			initvals.set(&assign_map, module);
367	
368			log("Finding identical cells in module `%s'.\n", module->name);
369	
370			// Use no more than one worker per thousand cells, rounded down, so
371			// we only start multithreading with at least 2000 cells.
372			int num_worker_threads = ThreadPool::pool_size(0, module->cells_size()/1000);
373			int workers = std::max(1, num_worker_threads);
374	
375			// The main thread doesn't do any work, so if there is only one worker thread,
376			// just run everything on the main thread instead.
377			// This avoids creating and waiting on a thread, which is pretty high overhead
378			// for very small modules.
379			if (num_worker_threads == 1)
380				num_worker_threads = 0;
381			OptMergeThreadWorker thread_worker(module, initvals, assign_map, ct, workers, mode_share_all, mode_keepdc);
382	
383			std::vector<ConcurrentQueue<CellRange>> cell_ranges_queues(num_worker_threads);
384			std::vector<ConcurrentQueue<CellHashes>> cell_hashes_queues(num_worker_threads);
385			std::vector<ConcurrentQueue<Shards>> shards_queues(num_worker_threads);
386			std::vector<ConcurrentQueue<FoundDuplicates>> duplicates_queues(num_worker_threads);
387	
388			ThreadPool thread_pool(num_worker_threads, [&](int i) {
389				while (std::optional<CellRange> c = cell_ranges_queues[i].pop_front()) {
390					cell_hashes_queues[i].push_back(thread_worker.compute_cell_hashes(*c));
391					std::optional<Shards> shards = shards_queues[i].pop_front();
392					duplicates_queues[i].push_back(thread_worker.find_duplicate_cells(i, *shards));
393				}
394			});
395	
396			bool did_something = true;
397			// A cell may have to go through a lot of collisions if the hash
398			// function is performing poorly, but it's a symptom of something bad
399			// beyond the user's control.
400			while (did_something)
401			{
402				int cells_size = module->cells_size();
403				log("Computing hashes of %d cells of `%s'.\n", cells_size, module->name);
404				std::vector<std::vector<std::vector<CellHash>>> sharded_bucketed_cell_hashes(workers);
405	
406				int cell_index = 0;
407				int cells_size_mod_workers = cells_size % workers;
408				{
409					Multithreading multithreading;
410					for (int i = 0; i < workers; ++i) {
411						int num_cells = cells_size/workers + ((i < cells_size_mod_workers) ? 1 : 0);
412						CellRange c = { cell_index, cell_index + num_cells };
413						cell_index += num_cells;
414						if (num_worker_threads > 0)
415							cell_ranges_queues[i].push_back(c);
416						else
417							sharded_bucketed_cell_hashes[i] = std::move(thread_worker.compute_cell_hashes(c).bucketed_cell_hashes);
418					}
419					log_assert(cell_index == cells_size);
420					if (num_worker_threads > 0)
421						for (int i = 0; i < workers; ++i)
422							sharded_bucketed_cell_hashes[i] = std::move(cell_hashes_queues[i].pop_front()->bucketed_cell_hashes);
423				}
424	
425				log("Finding duplicate cells in `%s'.\n", module->name);
426				std::vector<DuplicateCell> merged_duplicates;
427				{
428					Multithreading multithreading;
429					for (int i = 0; i < workers; ++i) {
430						Shards thread_shards = { sharded_bucketed_cell_hashes };
431						if (num_worker_threads > 0)
432							shards_queues[i].push_back(thread_shards);
433						else {
434							std::vector<DuplicateCell> d = std::move(thread_worker.find_duplicate_cells(i, thread_shards).duplicates);
435							merged_duplicates.insert(merged_duplicates.end(), d.begin(), d.end());
436						}
437					}
438					if (num_worker_threads > 0)
439						for (int i = 0; i < workers; ++i) {
440							std::vector<DuplicateCell> d = std::move(duplicates_queues[i].pop_front()->duplicates);
441							merged_duplicates.insert(merged_duplicates.end(), d.begin(), d.end());
442						}
443				}
444				std::sort(merged_duplicates.begin(), merged_duplicates.end(), [](const DuplicateCell &lhs, const DuplicateCell &rhs) {
445					// Sort them by the order in which duplicates would have been detected in a single-threaded
446					// run. The cell at which the duplicate would have been detected is the latter of the two
447					// cells involved.
448					return std::max(lhs.remove_cell, lhs.keep_cell) < std::max(rhs.remove_cell, rhs.keep_cell);
449				});
450	
451				// Convert to cell pointers because removing cells will invalidate the indices.
452				std::vector<std::pair<RTLIL::Cell*, RTLIL::Cell*>> cell_ptrs;
453				for (DuplicateCell dup : merged_duplicates)
454					cell_ptrs.push_back({module->cell_at(dup.remove_cell), module->cell_at(dup.keep_cell)});
455	
456				for (auto [remove_cell, keep_cell] : cell_ptrs)
457				{
458					log_debug("  Cell `%s' is identical to cell `%s'.\n", remove_cell->name, keep_cell->name);
459					for (auto &it : remove_cell->connections()) {
460						if (remove_cell->output(it.first)) {
461							RTLIL::SigSpec keep_sig = keep_cell->getPort(it.first);
462							log_debug("    Redirecting output %s: %s = %s\n", it.first,
463									log_signal(it.second), log_signal(keep_sig));
464							Const init = initvals(keep_sig);
465							initvals.remove_init(it.second);
466							initvals.remove_init(keep_sig);
467							module->connect(RTLIL::SigSig(it.second, keep_sig));
468							auto keep_sig_it = keep_sig.begin();
469							for (SigBit remove_sig_bit : it.second) {
470								assign_map.add(remove_sig_bit, *keep_sig_it);
471								++keep_sig_it;
472							}
473							initvals.set_init(keep_sig, init);
474						}
475					}
476					log_debug("    Removing %s cell `%s' from module `%s'.\n", remove_cell->type, remove_cell->name, module->name);
477					module->remove(remove_cell);
478					total_count++;
479				}
480				did_something = !merged_duplicates.empty();
481			}
482	
483			for (ConcurrentQueue<CellRange> &q : cell_ranges_queues)
484				q.close();
485	
486			for (ConcurrentQueue<Shards> &q : shards_queues)
487				q.close();
488	
489			for (ConcurrentQueue<CellRange> &q : cell_ranges_queues)
490				q.close();
491	
492			for (ConcurrentQueue<Shards> &q : shards_queues)
493				q.close();
494	
495			log_suppressed();
496		}
497	};
498	
499	struct OptMergePass : public Pass {
500		OptMergePass() : Pass("opt_merge", "consolidate identical cells") { }
501		void help() override
502		{
503			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
504			log("\n");
505			log("    opt_merge [options] [selection]\n");
506			log("\n");
507			log("This pass identifies cells with identical type and input signals. Such cells\n");
508			log("are then merged to one cell.\n");
509			log("\n");
510			log("    -nomux\n");
511			log("        Do not merge MUX cells.\n");
512			log("\n");
513			log("    -share_all\n");
514			log("        Operate on all cell types, not just built-in types.\n");
515			log("\n");
516			log("    -keepdc\n");
517			log("        Do not merge flipflops with don't-care bits in their initial value.\n");
518			log("\n");
519		}
520		void execute(std::vector<std::string> args, RTLIL::Design *design) override
521		{
522			log_header(design, "Executing OPT_MERGE pass (detect identical cells).\n");
523	
524			bool mode_nomux = false;
525			bool mode_share_all = false;
526			bool mode_keepdc = false;
527	
528			size_t argidx;
529			for (argidx = 1; argidx < args.size(); argidx++) {
530				std::string arg = args[argidx];
531				if (arg == "-nomux") {
532					mode_nomux = true;
533					continue;
534				}
535				if (arg == "-share_all") {
536					mode_share_all = true;
537					continue;
538				}
539				if (arg == "-keepdc") {
540					mode_keepdc = true;
541					continue;
542				}
543				break;
544			}
545			extra_args(args, argidx, design);
546	
547			CellTypes ct;
548			ct.setup_internals();
549			ct.setup_internals_mem();
550			ct.setup_stdcells();
551			ct.setup_stdcells_mem();
552			if (mode_nomux) {
553				ct.cell_types.erase(ID($mux));
554				ct.cell_types.erase(ID($pmux));
555			}
556			ct.cell_types.erase(ID($tribuf));
557			ct.cell_types.erase(ID($_TBUF_));
558			ct.cell_types.erase(ID($anyseq));
559			ct.cell_types.erase(ID($anyconst));
560			ct.cell_types.erase(ID($allseq));
561			ct.cell_types.erase(ID($allconst));
562	
563			int total_count = 0;
564			for (auto module : design->selected_modules()) {
565				OptMergeWorker worker(module, ct, mode_share_all, mode_keepdc);
566				total_count += worker.total_count;
567			}
568	
569			if (total_count)
570				design->scratchpad_set_bool("opt.did_something", true);
571			log("Removed a total of %d cells.\n", total_count);
572		}
573	} OptMergePass;
574	
575	PRIVATE_NAMESPACE_END
