494			for (auto &conn : cell->connections())
495			if (yosys_celltypes.cell_output(cell->type, conn.first))
496			for (auto bit : assign_map(conn.second))
497				outbit_to_cell[bit] = cell;
498			cells.node(cell);
499		}
500	
501		for (auto cell : module->cells())
502		if (design->selected(module, cell) && yosys_celltypes.cell_evaluable(cell->type)) {
503			const int r_index = cells.node(cell);
504			for (auto &conn : cell->connections())
505			if (yosys_celltypes.cell_input(cell->type, conn.first))
506			for (auto bit : assign_map(conn.second))
507			if (outbit_to_cell.count(bit))
508				cells.edge(cells.node(outbit_to_cell.at(bit)), r_index);
509		}
510	
511		if (!cells.sort()) {
512			// There might be a combinational loop, or there might be constants on the output of cells. 'check' may find out more.
513			// ...unless this is a coarse-grained cell loop, but not a bit loop, in which case it won't, and all is good.
514			log("Couldn't topologically sort cells, optimizing module %s may take a longer time.\n", module);
515		}
516	
517		for (auto cell : cells.sorted)
518		{
519	#define ACTION_DO(_p_, _s_) do { replace_cell(assign_map, module, cell, input.as_string(), _p_, _s_); goto next_cell; } while (0)
520	#define ACTION_DO_Y(_v_) ACTION_DO(ID::Y, RTLIL::SigSpec(RTLIL::State::S ## _v_))
521	
522			bool detect_const_and = false;
523			bool detect_const_or = false;
524	
525			if (cell->type.in(ID($reduce_and), ID($_AND_)))
526				detect_const_and = true;
527	
528			if (cell->type.in(ID($and), ID($logic_and)) && GetSize(cell->getPort(ID::A)) == 1 && GetSize(cell->getPort(ID::B)) == 1 && !cell->getParam(ID::A_SIGNED).as_bool())
529				detect_const_and = true;
530	
531			if (cell->type.in(ID($reduce_or), ID($reduce_bool), ID($_OR_)))
532				detect_const_or = true;
533	
534			if (cell->type.in(ID($or), ID($logic_or)) && GetSize(cell->getPort(ID::A)) == 1 && GetSize(cell->getPort(ID::B)) == 1 && !cell->getParam(ID::A_SIGNED).as_bool())
535				detect_const_or = true;
536	
537			if (detect_const_and || detect_const_or)
538			{
539				pool<SigBit> input_bits = assign_map(cell->getPort(ID::A)).to_sigbit_pool();
540				bool found_zero = false, found_one = false, found_undef = false, found_inv = false, many_conconst = false;
541				SigBit non_const_input = State::Sm;
542	
543				if (cell->hasPort(ID::B)) {
544					vector<SigBit> more_bits = assign_map(cell->getPort(ID::B)).to_sigbit_vector();
545					input_bits.insert(more_bits.begin(), more_bits.end());
546				}
547	
548				for (auto bit : input_bits) {
549					if (bit.wire) {
550						if (invert_map.count(bit) && input_bits.count(invert_map.at(bit)))
551							found_inv = true;
552						if (non_const_input != State::Sm)
553							many_conconst = true;
554						non_const_input = many_conconst ? State::Sm : bit;
555					} else {
556						if (bit == State::S0)
557							found_zero = true;
558						else if (bit == State::S1)
559							found_one = true;
560						else
561							found_undef = true;
562					}
563				}
564	
565				if (detect_const_and && (found_zero || found_inv || (found_undef && consume_x))) {
566					replace_cell(assign_map, module, cell, "const_and", ID::Y, RTLIL::State::S0);
567					goto next_cell;
568				}
